INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '49bb18b6-40c4-4b0c-9661-6a5e1c810bb3',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS Compute Models — Picking Between EC2, ECS, Lambda, and CloudFront Functions$escape$,
  $escape$EC2 gives you full control — choose it when you need persistent processes, custom runtimes, or GPU workloads (e.g., g4dn for ML inference). Use Auto Scaling Groups with launch templates for elasticity. ECS on Fargate removes instance management while keeping container semantics — ideal for long-running microservices, background workers, or anything needing >15 min execution. Lambda is the right call for event-driven workloads: S3 triggers, API Gateway backends, SQS consumers. Cold starts bite you on Java/C# — use Provisioned Concurrency or snap-start (Java 21 on Graviton). Lambda's 10 GB memory ceiling and 15-min timeout are hard walls. CloudFront Functions run at 225+ PoPs in sub-millisecond for request manipulation (URL rewrites, A/B headers) — but no network I/O. Lambda@Edge adds full Node.js/Python runtime at the edge with VPC access, at higher latency cost. The decision tree: stateful/GPU → EC2; containerized long-running → Fargate; event-driven <15min → Lambda; pure request transform → CloudFront Functions; edge logic with I/O → Lambda@Edge.$escape$,
  $escape$# Deploy a Lambda function with Provisioned Concurrency to eliminate cold starts
aws lambda create-function \
  --function-name order-processor \
  --runtime python3.12 \
  --role arn:aws:iam::123456789012:role/lambda-exec \
  --handler app.handler \
  --zip-file fileb://function.zip

aws lambda publish-version \
  --function-name order-processor

aws lambda put-provisioned-concurrency-config \
  --function-name order-processor \
  --qualifier 1 \
  --provisioned-concurrent-executions 10$escape$,
  $escape$bash$escape$,
