INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a6b41acd-d679-49c4-94a8-e808cbd5b9b1',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS VPC — Locking Down Traffic Between ALB and Private Subnets$escape$,
  $escape$A production-grade AWS VPC splits resources across public and private subnets in at least two AZs. Your ALB lives in public subnets (internet-facing), EC2 or ECS tasks in private subnets — never expose compute directly. Security groups are stateful and instance-scoped; NACLs are stateless and subnet-scoped. The right pattern: ALB security group allows inbound 443 from 0.0.0.0/0, and your app security group allows inbound on your app port *only from the ALB security group ID* — not a CIDR. This locks lateral movement even inside the VPC. Private subnets route outbound via a NAT Gateway in the public subnet; never attach an IGW route to a private subnet. For DNS, use Route 53 Alias records (not CNAME) to point your apex domain to the ALB — Alias records are free, resolve at AWS edge, and support the zone apex. Enable VPC DNS resolution (`enableDnsSupport`, `enableDnsHostnames`) or private hosted zones won't resolve. For inter-service traffic, use VPC endpoints (Interface or Gateway) to avoid NAT costs on calls to S3, DynamoDB, or SSM.$escape$,
  $escape$# Allow app tier to accept traffic ONLY from ALB security group
aws ec2 authorize-security-group-ingress \
  --group-id sg-0app1234567890abc \
  --protocol tcp \
  --port 8080 \
  --source-group sg-0alb1234567890abc

# Create Route 53 Alias record pointing apex domain to ALB
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890ABC \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "example.com",
        "Type": "A",
        "AliasTarget": {
          "HostedZoneId": "Z35SXDOTRQ7X7K",
          "DNSName": "my-alb-123.us-east-1.elb.amazonaws.com",
          "EvaluateTargetHealth": true
        }
      }
    }]
  }'$escape$,
