INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a3d6a5d5-829f-4d78-940e-a57818103211',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS RDS — Read Replicas, Automated Backups, and Multi-AZ Without the Ops Burden$escape$,
  $escape$RDS eliminates manual DB operations while giving you production-grade durability. For read scaling, create a read replica with a single API call — RDS uses async binlog replication for MySQL/MariaDB and async streaming replication for PostgreSQL. Promote a replica to standalone in a DR scenario via `promote-read-replica`. Multi-AZ deployments use synchronous replication to a standby in a separate AZ; failover is automatic and typically completes in 60–120 seconds with a DNS flip — your connection string stays the same.

Automated backups use incremental snapshots to S3, retained 1–35 days. Point-in-time recovery (PITR) restores to any second within the retention window by replaying transaction logs against the nearest snapshot. Note: restores always create a new DB instance — you can't restore in-place. For Aurora specifically, `BacktrackWindow` lets you rewind the cluster up to 72 hours without a full restore, which is significantly faster for accidental data mutations.$escape$,
  $escape$aws rds create-db-instance-read-replica \
  --db-instance-identifier prod-postgres-replica \
  --source-db-instance-identifier prod-postgres \
  --db-instance-class db.r6g.large \
  --availability-zone us-east-1b

# Restore to a point in time (creates new instance)
aws rds restore-db-instance-to-point-in-time \
  --source-db-instance-identifier prod-postgres \
  --target-db-instance-identifier prod-postgres-restored \
  --restore-time 2026-04-17T03:00:00Z$escape$,
  $escape$bash$escape$,
