INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '99138f69-9f9b-4495-a54c-a7034df12b58',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS Cost Optimization — Reserved vs Spot vs On-Demand, Rightsizing, and Budget Alerts$escape$,
  $escape$AWS pricing has three compute purchase models: On-Demand (pay-per-second, no commitment), Reserved Instances (1- or 3-year commitment, up to 72% savings), and Spot (spare capacity, up to 90% savings but interruptible with a 2-minute warning). Use On-Demand for unpredictable or short-lived workloads. Commit to Reserved Instances (Standard or Convertible) for steady-state services like RDS or always-on EC2 — Convertible RIs let you swap instance families. Run batch jobs, stateless workers, and fault-tolerant services on Spot via EC2 Auto Scaling mixed-instance policies with `SpotAllocationStrategy: capacity-optimized`.

Rightsizing is the highest-ROI lever: AWS Compute Optimizer analyzes CloudWatch utilization and flags over-provisioned instances. Run it via `compute-optimizer get-ec2-instance-recommendations`. For containers, use ECS Fargate right-sizing reports in Cost Explorer.

Set proactive guardrails with AWS Budgets: create cost and usage budgets with SNS-triggered alerts at 80% and 100% thresholds. Use Cost Anomaly Detection (`aws ce create-anomaly-monitor`) to catch unexpected spend spikes before they compound.$escape$,
  $escape$#!/usr/bin/env bash
# Create a monthly cost budget with SNS alerts at 80% and 100%
aws budgets create-budget \
  --account-id "$(aws sts get-caller-identity --query Account --output text)" \
  --budget '{
    "BudgetName": "monthly-ec2-budget",
    "BudgetLimit": {"Amount": "500", "Unit": "USD"},
    "TimeUnit": "MONTHLY",
    "BudgetType": "COST"
  }' \
  --notifications-with-subscribers '[{
    "Notification": {"NotificationType": "ACTUAL", "ComparisonOperator": "GREATER_THAN", "Threshold": 80},
    "Subscribers": [{"SubscriptionType": "SNS", "Address": "arn:aws:sns:us-east-1:123456789012:cost-alerts"}]
  }]'

# Get Compute Optimizer rightsizing recommendations
aws compute-optimizer get-ec2-instance-recommendations \
  --filters name=Finding,values=Overprovisioned \
  --query 'instanceRecommendations[*].{Instance:instanceArn,Current:currentInstanceType,Recommended:recommendationOptions[0].instanceType}'$escape$,
  $escape$bash$escape$,
