INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6fa97db6-74ef-4acc-85a7-6ec6f1d6e509',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS CloudFront — Cache Setup, Invalidation, and Edge Strategy That Actually Works$escape$,
  $escape$CloudFront distributions serve content from 600+ edge locations, but default cache behavior is often misconfigured. Set cache policies using managed policies like `CachingOptimized` (TTL: 86400s) for static assets, and `CachingDisabled` for API origins. Avoid origin-level cache headers overriding your distribution policy — use "Cache policy" over "Use origin cache headers" in behavior settings.

For fine-grained control, create custom cache policies via the Console or CLI, specifying `min-ttl`, `default-ttl`, and `max-ttl` independently. Use `Cache-Control: s-maxage` at the origin to override CloudFront TTL without affecting browser cache.

Invalidations are charged after 1,000 paths/month — use versioned file paths (`main.abc123.js`) instead of frequent `/*` invalidations. When you must invalidate, scope paths tightly: `/static/js/*` beats `/*`.

For dynamic content, configure origin request policies to forward only necessary headers/cookies — forwarding `Cookie: *` disables caching entirely. Use Lambda@Edge or CloudFront Functions for request manipulation at sub-millisecond latency at the edge, keeping heavy logic in Lambda@Edge (viewer/origin request hooks) and lightweight rewrites in CloudFront Functions.$escape$,
  $escape$aws cloudfront create-invalidation \
  --distribution-id E1EXAMPLE \
  --paths "/static/js/*" "/static/css/*"

# Create a cache policy with custom TTLs
aws cloudfront create-cache-policy \
  --cache-policy-config '{
    "Name": "CustomStaticPolicy",
    "DefaultTTL": 86400,
    "MaxTTL": 31536000,
    "MinTTL": 0,
    "ParametersInCacheKeyAndForwardedToOrigin": {
      "EnableAcceptEncodingGzip": true,
      "EnableAcceptEncodingBrotli": true,
      "HeadersConfig": {"HeaderBehavior": "none"},
      "CookiesConfig": {"CookieBehavior": "none"},
      "QueryStringsConfig": {"QueryStringBehavior": "none"}
    }
  }'$escape$,
  $escape$bash$escape$,
