INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '93fb2ddf-8edf-4b4a-9edd-31dcf7f0af89',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS Lambda Cold Starts — Minimizing Latency, Respecting Limits$escape$,
  $escape$Cold starts occur when Lambda provisions a new execution environment: downloads your package, starts the runtime, and runs initialization code outside your handler. For Node.js this typically adds 200–500ms; for Java with Spring it can hit 3–10s. Provisioned Concurrency eliminates cold starts by keeping environments warm — configure it on a published version or alias, not $LATEST. Lambda's hard timeout ceiling is 15 minutes; anything longer belongs in Step Functions or ECS. Because each invocation may hit a different environment, never rely on in-memory state across calls. Use `/tmp` (512MB–10GB ephemeral, per-environment) only for single-invocation scratch space, not shared cache. Connection pooling to RDS must use RDS Proxy — raw connections held in the handler scope survive warm invocations but leak under concurrency bursts. Keep deployment packages under 50MB zipped; larger packages directly inflate init duration. Use Lambda Layers to share dependencies without bloating each function's package, and enable SnapStart for Java 21 runtimes to snapshot post-init state and restore it on subsequent cold starts.$escape$,
  $escape$# Provision concurrency on an alias to eliminate cold starts
aws lambda put-provisioned-concurrency-config \
  --function-name my-api \
  --qualifier prod \
  --provisioned-concurrent-executions 10

# Check init duration vs billed duration in a recent invocation
aws logs filter-log-events \
  --log-group-name /aws/lambda/my-api \
  --filter-pattern '"Init Duration"' \
  --query 'events[*].message' \
  --output text | head -5$escape$,
  $escape$bash$escape$,
