INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '81f5a175-4861-4607-9407-b232e8208789',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS Edge Computing — Lambda@Edge vs CloudFront Functions for Latency-Critical Apps$escape$,
  $escape$AWS offers two edge compute primitives via CloudFront: CloudFront Functions and Lambda@Edge. Both execute at CloudFront's 400+ Points of Presence instead of your origin region, cutting round-trip latency for globally distributed users — the same latency win Cloudflare Workers and Vercel Edge provide, but within the AWS ecosystem.

CloudFront Functions are sub-millisecond JS runtimes ideal for lightweight work — URL rewrites, header normalization, simple geo-redirects. They hook into viewer-request and viewer-response events only, with a 2MB code limit and ~$0.10/million invocations.

Lambda@Edge runs full Node.js 18.x or Python 3.12 with up to 128MB memory across all four CloudFront events (viewer-request, origin-request, origin-response, viewer-response). The killer use case: JWT validation at the viewer-request stage means auth runs at the nearest PoP — your us-east-1 origin never receives unauthenticated traffic. For users in APAC or Europe, this eliminates a 200–400ms transatlantic round-trip on every authenticated request.

Deploy Lambda@Edge functions exclusively to us-east-1; CloudFront auto-replicates them globally. After updates, run aws cloudfront create-invalidation to force propagation across all PoPs.$escape$,
  $escape$// Lambda@Edge — Viewer Request handler (deploy to us-east-1)
import { verify } from 'jsonwebtoken';

export const handler = async (event) => {
  const { request } = event.Records[0].cf;
  const authHeader = request.headers['authorization']?.[0]?.value ?? '';
  const token = authHeader.replace('Bearer ', '');

  try {
    verify(token, process.env.JWT_SECRET);
    return request; // Forward authenticated request to ALB/S3 origin
  } catch {
    return {
      status: '401',
      statusDescription: 'Unauthorized',
      body: JSON.stringify({ error: 'Invalid token' }),
      headers: { 'content-type': [{ key: 'Content-Type', value: 'application/json' }] },
    };
  }
};$escape$,
  $escape$javascript$escape$,
