INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a1211306-2e72-4910-99a2-0bad79ebdbed',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS Security Hardening — Encryption, Secrets Manager, WAF, and Shield in Practice$escape$,
  $escape$AWS encrypts S3, RDS, and EBS at rest via KMS — but you must opt in. Use `aws:kms` as your S3 default encryption algorithm and enforce it with a bucket policy denying `s3:PutObject` unless `x-amz-server-side-encryption: aws:kms` is present. For secrets, never use SSM Parameter Store plain strings — store DB credentials and API keys in Secrets Manager with automatic rotation via the built-in Lambda rotator. Reference them in ECS task definitions using `secrets:` blocks; the value never touches your environment variables as plaintext. In-transit: enforce TLS 1.2+ on ALBs by setting a security policy of `ELBSecurityPolicy-TLS13-1-2-2021-06`. For WAF, attach an `AWS::WAFv2::WebACL` to your CloudFront distribution with the `AWSManagedRulesCommonRuleSet` and `AWSManagedRulesKnownBadInputsRuleSet` — these catch SQLi, XSS, and Log4Shell patterns without custom rules. DDoS protection upgrades from Shield Standard (free, automatic) to Shield Advanced for SLA-backed response and cost protection on Route 53, CloudFront, and ALBs. Enable it per resource, not globally.$escape$,
  $escape$# Deny S3 uploads without KMS encryption
aws s3api put-bucket-policy --bucket my-prod-bucket --policy '{
  "Version": "2012-10-17",
  "Statement": [{
    "Effect": "Deny",
    "Principal": "*",
    "Action": "s3:PutObject",
    "Resource": "arn:aws:s3:::my-prod-bucket/*",
    "Condition": {
      "StringNotEquals": {
        "s3:x-amz-server-side-encryption": "aws:kms"
      }
    }
  }]
}'$escape$,
  $escape$bash$escape$,
