INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '53726b4b-839d-4e22-9b5c-26a18d0319c3',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS IaaS vs PaaS (Railway/Vercel/Fly.io) — What You're Actually Trading$escape$,
  $escape$When you deploy to Fly.io or Railway, you're getting an opinionated wrapper around primitives that AWS exposes raw. Fly.io runs Firecracker VMs — functionally similar to EC2 Nitro — but abstracts the ALB, target groups, security groups, and VPC subnetting behind a single `fly deploy`. Vercel's Edge Network mirrors CloudFront + Lambda@Edge, minus the distribution config, cache behavior rules, and IAM trust policies you'd wire manually.

On raw AWS, a production ECS Fargate service touches: a VPC with public/private subnets, an ALB with listener rules, a target group with health check tuning, an ECS task definition (CPU/mem, log driver, secrets from SSM/Secrets Manager), a service with deployment circuit breakers, and IAM task roles scoped per service. That's real control — blue/green via CodeDeploy, Spot capacity with `capacityProviderStrategy`, cross-account ECR pulls — none of which PaaS exposes.

The break-even point: PaaS wins below ~$500/mo and under 3 engineers. Above that, raw AWS pays back through Reserved Instance pricing, VPC peering to RDS, and Savings Plans. You can't negotiate unit economics with Railway.$escape$,
  $escape$# PaaS: one command, done
fly deploy --dockerfile Dockerfile

# Raw AWS: equivalent surface area
aws ecs register-task-definition --cli-input-json file://task-def.json
aws ecs create-service \
  --cluster prod \
  --task-definition my-app:7 \
  --desired-count 3 \
  --capacity-provider-strategy '[{"capacityProvider":"FARGATE_SPOT","weight":2},{"capacityProvider":"FARGATE","weight":1}]' \
  --load-balancers '[{"targetGroupArn":"arn:aws:elasticloadbalancing:...","containerName":"app","containerPort":8080}]' \
  --deployment-configuration 'deploymentCircuitBreaker={enable=true,rollback=true}'$escape$,
  $escape$bash$escape$,
