INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '17174239-0054-4ce2-aa5a-b23cf77d9403',
  '00000000-0000-0000-0000-000000000001',
  $escape$AWS Region Selection — Latency, Data Residency, and Compliance Done Right$escape$,
  $escape$Picking an AWS region isn't just about proximity — it's a three-way tradeoff between latency, data residency laws, and service availability. Start with `aws ec2 describe-regions` to list enabled regions, then use CloudWatch Internet Monitor or Route 53 Latency Routing policies to measure real-world latency from your user base — don't rely on ping alone. For data residency, GDPR mandates EU data stay in EU regions (eu-west-1, eu-central-1, eu-north-1); HIPAA workloads need a BAA with AWS, but any region qualifies if controls are in place. FedRAMP High is limited to us-east-1 and us-west-2 GovCloud variants. Use AWS Config rule `restricted-ec2-region` (or an SCP in AWS Organizations) to enforce region boundaries at the account level — this prevents accidental resource creation outside approved regions. Multi-region architectures should use Global Tables (DynamoDB), Aurora Global Database, or S3 Cross-Region Replication with SSE-KMS. Always verify service availability per region via the AWS Regional Services List before committing to an architecture — not all services are GA everywhere.$escape$,
  $escape$# Enforce allowed regions via AWS Organizations SCP (JSON policy)
aws organizations create-policy \
  --name "EnforceApprovedRegions" \
  --type SERVICE_CONTROL_POLICY \
  --description "Restrict resource creation to approved regions" \
  --content '{
    "Version": "2012-10-17",
    "Statement": [{
      "Effect": "Deny",
      "Action": "*",
      "Resource": "*",
      "Condition": {
        "StringNotEquals": {
          "aws:RequestedRegion": ["us-east-1", "eu-west-1", "ap-southeast-1"]
        }
      }
    }]
  }'$escape$,
  $escape$bash$escape$,
